import jwt from 'jsonwebtoken';
import { NextRequest, NextResponse } from 'next/server';

const JWT_SECRET = process.env.JWT_SECRET || 'pps-payroll-super-secret-jwt-key-2026';

export interface TokenPayload {
  userId: string;
  email: string;
  role: string;
  name: string;
}

export function generateToken(payload: TokenPayload): string {
  return jwt.sign(payload, JWT_SECRET, { expiresIn: '1d' });
}

export function verifyToken(token: string): TokenPayload | null {
  try {
    return jwt.verify(token, JWT_SECRET) as TokenPayload;
  } catch (error) {
    return null;
  }
}

export function getUserFromRequest(req: NextRequest): TokenPayload | null {
  // Try to get token from header or cookie
  let token = '';
  
  const authHeader = req.headers.get('Authorization');
  if (authHeader && authHeader.startsWith('Bearer ')) {
    token = authHeader.substring(7);
  } else {
    const cookieToken = req.cookies.get('pps-auth-token')?.value;
    if (cookieToken) {
      token = cookieToken;
    }
  }

  if (!token) return null;
  return verifyToken(token);
}

export function authMiddleware(req: NextRequest) {
  const user = getUserFromRequest(req);
  if (!user) {
    return { error: 'Unauthorized: Invalid or missing token', status: 401 };
  }
  return { user };
}

export function roleGuard(user: TokenPayload, allowedRoles: string[]) {
  if (!allowedRoles.includes(user.role)) {
    return { error: 'Forbidden: Insufficient permissions', status: 403 };
  }
  return {};
}
