import bcrypt from 'bcryptjs';

// In-memory mock database models
export interface Department {
  id: string;
  name: string;
  description: string | null;
}

export interface Designation {
  id: string;
  title: string;
  level: number;
}

export interface User {
  id: string;
  name: string;
  email: string;
  passwordHash: string;
  role: string;
  avatar: string | null;
  createdAt: Date;
  updatedAt: Date;
}

export interface Employee {
  id: string;
  employeeCode: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string | null;
  departmentId: string | null;
  designationId: string | null;
  joiningDate: Date;
  salary: number;
  status: string;
  avatar?: string | null;
  managerId: string | null;
  userId: string | null;
}

export interface Attendance {
  id: string;
  employeeId: string;
  checkIn: Date;
  checkOut: Date | null;
  totalHours: number | null;
  attendanceStatus: string;
  date: Date;
}

export interface Payroll {
  id: string;
  employeeId: string;
  baseSalary: number;
  allowances: number;
  bonus: number;
  deductions: number;
  tax: number;
  netSalary: number;
  payrollMonth: string;
  paymentStatus: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface Leave {
  id: string;
  employeeId: string;
  leaveType: string;
  startDate: Date;
  endDate: Date;
  reason: string | null;
  approvalStatus: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface Notification {
  id: string;
  userId: string;
  title: string;
  message: string;
  isRead: boolean;
  createdAt: Date;
}

export interface ActivityLog {
  id: string;
  userId: string;
  action: string;
  metadata: any;
  createdAt: Date;
}

// Global in-memory storage (singleton structure)
class MockDatabase {
  departments: Department[] = [];
  designations: Designation[] = [];
  users: User[] = [];
  employees: Employee[] = [];
  attendance: Attendance[] = [];
  payrolls: Payroll[] = [];
  leaves: Leave[] = [];
  notifications: Notification[] = [];
  activityLogs: ActivityLog[] = [];
  initialized = false;

  constructor() {
    this.init();
  }

  init() {
    if (this.initialized) return;

    console.log('⚡ Initializing In-Memory Fallback Database Store...');

    // Departments
    this.departments = [
      { id: 'dept-eng', name: 'Engineering', description: 'Software engineering and IT support' },
      { id: 'dept-hr', name: 'Human Resources', description: 'HR management and recruiting' },
      { id: 'dept-sales', name: 'Sales & Marketing', description: 'Product sales and brand marketing' },
      { id: 'dept-fin', name: 'Finance', description: 'Payroll, taxation, and accounts' },
    ];

    // Designations
    this.designations = [
      { id: 'des-eng', title: 'Software Engineer', level: 2 },
      { id: 'des-lead', title: 'Tech Lead', level: 3 },
      { id: 'des-hr', title: 'HR Manager', level: 3 },
      { id: 'des-admin', title: 'Administrator', level: 4 },
      { id: 'des-assoc', title: 'Associate', level: 1 },
    ];

    // Users
    const adminHash = bcrypt.hashSync('MAN@1234', 10);
    const empHash = bcrypt.hashSync('man@1234', 10);

    this.users = [
      {
        id: 'usr-admin',
        name: 'Man Patel',
        email: 'man@pps.com',
        passwordHash: adminHash,
        role: 'ADMIN',
        avatar: '/avatars/man_patel.jpg',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      {
        id: 'usr-rahul',
        name: 'Rahul Sharma',
        email: 'rahul@pps.com',
        passwordHash: empHash,
        role: 'EMPLOYEE',
        avatar: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      {
        id: 'usr-priya',
        name: 'Priya Mehta',
        email: 'priya@pps.com',
        passwordHash: empHash,
        role: 'HR',
        avatar: null,
        createdAt: new Date(),
        updatedAt: new Date(),
      },
    ];

    // Employees
    this.employees = [
      {
        id: 'emp-1',
        employeeCode: 'EMP001',
        firstName: 'Man',
        lastName: 'Patel',
        email: 'man@pps.com',
        phone: '+919876543210',
        joiningDate: new Date('2024-01-15'),
        salary: 150000,
        status: 'ACTIVE',
        userId: 'usr-admin',
        departmentId: 'dept-fin',
        designationId: 'des-admin',
        managerId: null,
      },
      {
        id: 'emp-2',
        employeeCode: 'EMP002',
        firstName: 'Rahul',
        lastName: 'Sharma',
        email: 'rahul@pps.com',
        phone: '+919876543211',
        joiningDate: new Date('2024-06-10'),
        salary: 80000,
        status: 'ACTIVE',
        userId: 'usr-rahul',
        departmentId: 'dept-eng',
        designationId: 'des-eng',
        managerId: 'emp-1',
      },
      {
        id: 'emp-3',
        employeeCode: 'EMP003',
        firstName: 'Priya',
        lastName: 'Mehta',
        email: 'priya@pps.com',
        phone: '+919876543212',
        joiningDate: new Date('2025-02-01'),
        salary: 65000,
        status: 'ACTIVE',
        userId: 'usr-priya',
        departmentId: 'dept-hr',
        designationId: 'des-hr',
        managerId: 'emp-1',
      },
    ];

    // Generate 125 more to total 128
    const names = [
      { first: 'Aarav', last: 'Singh' }, { first: 'Aditya', last: 'Verma' }, { first: 'Amit', last: 'Sharma' },
      { first: 'Ananya', last: 'Iyer' }, { first: 'Arjun', last: 'Reddy' }, { first: 'Dev', last: 'Joshi' },
      { first: 'Diya', last: 'Patel' }, { first: 'Ishaan', last: 'Gupta' }, { first: 'Kabir', last: 'Nair' },
      { first: 'Kavya', last: 'Rao' }, { first: 'Meera', last: 'Deshmukh' }, { first: 'Neha', last: 'Kapoor' },
      { first: 'Rohan', last: 'Mehta' }, { first: 'Saanvi', last: 'Bose' }, { first: 'Vivaan', last: 'Choudhury' }
    ];

    for (let i = 4; i <= 128; i++) {
      const namePair = names[(i - 4) % names.length];
      const deptId = i % 3 === 0 ? 'dept-eng' : (i % 3 === 1 ? 'dept-sales' : 'dept-hr');
      const desId = i % 2 === 0 ? 'des-eng' : 'des-assoc';
      const baseSalary = 30000 + (i % 10) * 5000;

      this.employees.push({
        id: `emp-${i}`,
        employeeCode: `EMP${String(i).padStart(3, '0')}`,
        firstName: namePair.first,
        lastName: `${namePair.last} ${i}`,
        email: `${namePair.first.toLowerCase()}.${i}@pps.com`,
        phone: `+91987654${String(i).padStart(4, '0')}`,
        joiningDate: new Date(`2024-${(i % 12) + 1}-01`),
        salary: baseSalary,
        status: 'ACTIVE',
        departmentId: deptId,
        designationId: desId,
        managerId: 'emp-1',
        userId: null,
      });
    }

    // Attendance (105 present, 23 absent on today 2026-05-26)
    const todayDate = new Date('2026-05-26');
    this.employees.forEach((emp, index) => {
      const isPresent = index < 105;
      const checkInTime = new Date('2026-05-26T09:00:00Z');
      
      if (index % 10 === 0 && isPresent) {
        checkInTime.setMinutes(45);
      } else if (isPresent) {
        checkInTime.setMinutes(index % 30);
      }

      const checkOutTime = isPresent ? new Date('2026-05-26T18:00:00Z') : null;
      const totalHours = isPresent ? (checkOutTime!.getTime() - checkInTime.getTime()) / (1000 * 60 * 60) : null;
      const status = !isPresent ? 'ABSENT' : (checkInTime.getMinutes() > 30 ? 'LATE' : 'PRESENT');

      this.attendance.push({
        id: `att-${index + 1}`,
        employeeId: emp.id,
        checkIn: isPresent ? checkInTime : new Date('2026-05-26T00:00:00Z'),
        checkOut: checkOutTime,
        totalHours: totalHours,
        attendanceStatus: status,
        date: todayDate,
      });
    });

    // Payroll May 2026 targets
    const targetBasicTotal = 2215600;
    const targetAllowancesTotal = 1245300;
    const targetBonusTotal = 693940;
    const targetDeductionsTotal = 721480;

    let accumulatedBasic = 0;
    let accumulatedAllowances = 0;
    let accumulatedBonus = 0;
    let accumulatedDeductions = 0;

    this.employees.forEach((emp, index) => {
      let basic = 0;
      let allowances = 0;
      let bonus = 0;
      let deductions = 0;

      if (index === 127) { // index 127 is the 128th employee
        basic = targetBasicTotal - accumulatedBasic;
        allowances = targetAllowancesTotal - accumulatedAllowances;
        bonus = targetBonusTotal - accumulatedBonus;
        deductions = targetDeductionsTotal - accumulatedDeductions;
      } else {
        const weight = emp.salary / 7000000;
        basic = Math.round(targetBasicTotal * weight);
        allowances = Math.round(targetAllowancesTotal * weight);
        bonus = Math.round(targetBonusTotal * (weight * (index % 2 === 0 ? 1.5 : 0.5)));
        deductions = Math.round(targetDeductionsTotal * (weight * (index % 3 === 0 ? 1.8 : 0.6)));

        accumulatedBasic += basic;
        accumulatedAllowances += allowances;
        accumulatedBonus += bonus;
        accumulatedDeductions += deductions;
      }

      const netSalary = basic + allowances + bonus - deductions;

      this.payrolls.push({
        id: `pay-${index + 1}-may`,
        employeeId: emp.id,
        baseSalary: basic,
        allowances: allowances,
        bonus: bonus,
        deductions: deductions,
        tax: Math.round(deductions * 0.4),
        netSalary: netSalary,
        payrollMonth: '2026-05',
        paymentStatus: 'PAID',
        createdAt: new Date('2026-05-25T10:00:00Z'),
        updatedAt: new Date('2026-05-25T10:00:00Z'),
      });
    });

    // Seed historical payrolls (Dec 2025 - Apr 2026) for the line chart
    const histMonths = ['2025-12', '2026-01', '2026-02', '2026-03', '2026-04'];
    const monthWeights = [0.82, 0.88, 0.84, 0.90, 0.95];

    histMonths.forEach((month, mIdx) => {
      const factor = monthWeights[mIdx];
      this.employees.forEach((emp, index) => {
        if (emp.joiningDate > new Date(`${month}-01`)) return;

        const basic = Math.round((emp.salary * 0.4) * factor);
        const allowances = Math.round((emp.salary * 0.25) * factor);
        const bonus = Math.round((emp.salary * 0.15) * factor * (index % 4 === 0 ? 1.2 : 0.8));
        const deductions = Math.round((emp.salary * 0.12) * factor * (index % 5 === 0 ? 1.4 : 0.7));
        const netSalary = basic + allowances + bonus - deductions;

        this.payrolls.push({
          id: `pay-${index + 1}-${month}`,
          employeeId: emp.id,
          baseSalary: basic,
          allowances: allowances,
          bonus: bonus,
          deductions: deductions,
          tax: Math.round(deductions * 0.4),
          netSalary: netSalary,
          payrollMonth: month,
          paymentStatus: 'PAID',
          createdAt: new Date(`${month}-28T10:00:00Z`),
          updatedAt: new Date(`${month}-28T10:00:00Z`),
        });
      });
    });

    // Leaves
    this.leaves = [
      {
        id: 'leave-1',
        employeeId: 'emp-2',
        leaveType: 'Casual',
        startDate: new Date('2026-05-10'),
        endDate: new Date('2026-05-12'),
        reason: 'Family function in hometown',
        approvalStatus: 'APPROVED',
        createdAt: new Date('2026-05-05'),
        updatedAt: new Date('2026-05-06'),
      },
      {
        id: 'leave-2',
        employeeId: 'emp-3',
        leaveType: 'Sick',
        startDate: new Date('2026-05-25'),
        endDate: new Date('2026-05-26'),
        reason: 'Fever and cold',
        approvalStatus: 'PENDING',
        createdAt: new Date('2026-05-24'),
        updatedAt: new Date('2026-05-24'),
      },
    ];

    // Notifications
    this.notifications = [
      {
        id: 'notif-1',
        userId: 'usr-admin',
        title: 'New Leave Request',
        message: 'Priya Mehta has requested Sick Leave from May 25 to May 26.',
        isRead: false,
        createdAt: new Date(Date.now() - 3600000),
      },
      {
        id: 'notif-2',
        userId: 'usr-admin',
        title: 'Payroll Processed',
        message: 'Payroll for May 2026 has been successfully processed.',
        isRead: true,
        createdAt: new Date(Date.now() - 7200000),
      },
    ];

    // Activity Logs
    const now = new Date();
    this.activityLogs = [
      {
        id: 'act-1',
        userId: 'usr-admin',
        action: 'PAYROLL_PROCESSED',
        metadata: { detail: 'Payroll for May 2026 processed', actor: 'System' },
        createdAt: new Date(now.getTime() - 2 * 60 * 60 * 1000),
      },
      {
        id: 'act-2',
        userId: 'usr-admin',
        action: 'LEAVE_APPROVED',
        metadata: { detail: 'Leave request approved', subject: 'Rahul Sharma', date: 'Apr 26' },
        createdAt: new Date(now.getTime() - 3 * 60 * 60 * 1000),
      },
      {
        id: 'act-3',
        userId: 'usr-admin',
        action: 'EMPLOYEE_ONBOARDED',
        metadata: { detail: 'New employee onboarded', subject: 'Priya Mehta', designation: 'HR Executive' },
        createdAt: new Date(now.getTime() - 24 * 60 * 60 * 1000),
      },
      {
        id: 'act-4',
        userId: 'usr-admin',
        action: 'TAX_UPDATE',
        metadata: { detail: 'Tax update for FY 2025-26', actor: 'System' },
        createdAt: new Date(now.getTime() - 2 * 24 * 60 * 60 * 1000),
      },
    ];

    this.initialized = true;
    console.log('✅ Fallback Store Seeded Successfully. 128 employees, 105 present, history loaded.');
  }
}

// Export a single instance to share in-memory state across requests during development
export const mockDb = new MockDatabase();
